IF NOT EXISTS (SELECT 1 FROM products WHERE slug = N'double_chicken_krispper_') INSERT INTO products (slug, title, description, thumb_url, main_image_url, hero_image_url, price_cents, is_featured, metadata_json) VALUES (N'double_chicken_krispper_', N'DOUBLE chicken KRISPPER ', N'È arrivato il Double Chicken Krispper — dove la doppia croccantezza del pollo incontra il doppio gusto del pollo arrosto, per un’esplosione di succosità mai provata prima.
Dimentica il solito panino al pollo: qui tutto è raddoppiato. All’esterno una doppia panatura dorata e super croccante, all’interno pollo tenero dal ricco sapore arrosto.
Il tutto esaltato dalla nostra salsa umami al rosmarino e da fresca lattuga croccante, per un equilibrio di gusto che conquista dal primo morso.
Un solo morso… e capirai subito la differenza per due.
Per informazioni su ingredienti, allergeni e caratteristiche dei prodotti, consulta il cartello ingredienti presente nella sezione “Allergeni”, disponibile a piè pagina del sito web.

